// Per-run options for this playbook. `task` seeds the FSM machine input
// (WorkflowInput); `cwd` is the working directory the deterministic `script`
// actor (CODE-1) runs in (slc/link.md §Script execution). Both optional.
export interface WorkflowPlaybookOptions extends WorkflowInput {
  cwd?: string;
}

function snapshotWorkflowOptions(value: unknown): WorkflowPlaybookOptions {
  const captured = snapshotJsonValue(value ?? {}, 'workflow runtime options');
  if (
    captured === null ||
    typeof captured !== 'object' ||
    Array.isArray(captured)
  ) {
    throw new TypeError('workflow runtime options must be an object');
  }
  const record = captured as Readonly<Record<string, JsonValue>>;
  const allowed = new Set(['task', 'cwd']);
  for (const [key, option] of Object.entries(record)) {
    if (!allowed.has(key)) {
      throw new TypeError(`workflow runtime options.${key} is not declared`);
    }
    if (typeof option !== 'string') {
      throw new TypeError(`workflow runtime options.${key} must be a string`);
    }
  }
  return captured as unknown as WorkflowPlaybookOptions;
}

const BOSS_REPLY_ERRORS = {
  missingQuestion: "needsBossReply outcome missing 'question' field",
  unregisteredState: (stateId: string) =>
    `state ${stateId} declared needsBossReply but is not registered as resumable`,
} as const;

// States that suspend a task pending a Boss reply (FSM RESUMABLE_STATE_IDS).
const RESUMABLE_STATE_IDS: ReadonlySet<string> = new Set([
  'implement',
  'review',
  'adjudicate',
  'rebut',
  'applyConclusion',
]);

// Working leaves that surface a human status on entry. `ready` and `done`
// stay silent (slc/link.md §Session lifecycle).
const SUPPRESSED_ENTRY_STATES: ReadonlySet<string> = new Set(['ready', 'done']);

