// Every runtime-value placeholder Source established, backed by a typed
// PlayerInput field (slc/gears2fsm.md §Setup). Substitution is one
// callback-based pass over the original template; replacement text is
// literal (no `$&`/`$$` interpretation), and placeholder-looking text inside
// a value is never re-substituted (slc/link.md §Output).
const PLACEHOLDER_FIELDS: ReadonlyArray<
  [placeholder: string, field: keyof PlayerInput]
> = [
  ['<task>', 'task'],
  ['<reviewFindings>', 'reviewFindings'],
  ['<reviewerRebuttal>', 'reviewerRebuttal'],
  ['<coderRuling>', 'coderRuling'],
  ['<conclusion>', 'conclusion'],
];

const PLACEHOLDER_PATTERN =
  /<task>|<reviewFindings>|<reviewerRebuttal>|<coderRuling>|<conclusion>/g;

// Player-prompt composer (slc/link.md §Player prompt composition).
// When the task resumes from its own Boss question, the continuation
// preamble and labelled Q/A blocks precede the domain body. The GEARS
// blockquote body is never re-flowed; only its placeholders are filled.
function composePlayerPrompt(input: PlayerInput): string {
  const blocks: string[] = [];
  if (
    input.pendingBossQuestion !== undefined &&
    input.bossReply !== undefined
  ) {
    blocks.push(
      'You previously paused this task to ask Boss a question; Boss has now replied. Continue the same task using the reply below.',
    );
    blocks.push(`Boss question:\n${input.pendingBossQuestion.question}`);
    blocks.push(`Boss reply:\n${input.bossReply}`);
  }

  const substitutions = new Map<string, string>();
  for (const [placeholder, field] of PLACEHOLDER_FIELDS) {
    const value = input[field];
    if (typeof value === 'string') substitutions.set(placeholder, value);
  }
  const body = input.prompt.replace(
    PLACEHOLDER_PATTERN,
    (match) => substitutions.get(match) ?? '',
  );
  blocks.push(body);

  return blocks.join('\n\n');
}

// Player-id resolver (slc/link.md §Player binding). Default binding: each
// player to its lowercased name; the Chinese names lowercase to themselves.
// The source declares no composite (aliased) players.
function resolvePlayerId(input: PlayerInput): string {
  return input.player.toLowerCase();
}

interface PendingBossQuestionShape {
  questionId: string;
  resumeStateId: string;
  sourceItem: string;
  player: string;
  question: string;
}

function pendingBossQuestionFromContext(
  context: Record<string, unknown>,
): PendingBossQuestionShape | undefined {
  const pending = context.pendingBossQuestion;
  if (
    pending === undefined ||
    typeof pending !== 'object' ||
    pending === null
  ) {
    return undefined;
  }
  const candidate = pending as Partial<
    Record<keyof PendingBossQuestionShape, unknown>
  >;
  if (
    typeof candidate.questionId !== 'string' ||
    typeof candidate.resumeStateId !== 'string' ||
    typeof candidate.sourceItem !== 'string' ||
    typeof candidate.player !== 'string' ||
    typeof candidate.question !== 'string'
  ) {
    return undefined;
  }
  return {
    questionId: candidate.questionId,
    resumeStateId: candidate.resumeStateId,
    sourceItem: candidate.sourceItem,
    player: candidate.player,
    question: candidate.question,
  };
}

// Required-field extraction (slc/link.md §Captain adjudication). Limited to
// the description's `Output shall include` / `输出应包含` clause; recognizes
// both the bare backticked name and the annotated `name: <...>` form.
function extractRequiredFields(description: string): string[] {
  const markers = ['Output shall include', '输出应包含'];
  let clauseStart = -1;
  for (const marker of markers) {
    const idx = description.indexOf(marker);
    if (idx !== -1) {
      clauseStart = idx + marker.length;
      break;
    }
  }
  if (clauseStart === -1) return [];
  const clause = description.slice(clauseStart);
  const fields: string[] = [];
  const re = /`([A-Za-z_$][A-Za-z0-9_$]*)(?::[^`]*)?`/g;
  for (const m of clause.matchAll(re)) fields.push(m[1]);
  return fields;
}

function buildJudgePrompt(input: PlayerInput, finalText: string): string {
  const lines: string[] = [];
  lines.push(`The ${input.player} just produced this output:`);
  lines.push('');
  lines.push('```');
  lines.push(finalText);
  lines.push('```');
  lines.push('');
  lines.push(
    'Pick exactly one outcome by `guard` and return JSON ' +
      '`{ guard, …payloadFields }`. Required payload fields are named in the ' +
      'outcome description after "Output shall include" / "输出应包含".',
  );
  lines.push('');
  for (const [key, description] of Object.entries(input.result)) {
    lines.push(`- \`${key}\` — ${description}`);
  }
  return lines.join('\n');
}

function isPlainObject(value: unknown): boolean {
  return typeof value === 'object' && value !== null && !Array.isArray(value);
}

function stripCodeFence(text: string): string {
  const fence = text.match(/^```(?:json)?\s*\n?([\s\S]*?)\n?```$/);
  return fence ? fence[1].trim() : text;
}

function dropTrailingComma(out: string): string {
  return out.replace(/,(\s*)$/, '$1');
}

// Scan the balanced JSON value rooted at `start`. Strict pass returns only a
// closed span; repair pass fixes a trailing comma, an unterminated string,
// and unclosed brackets (slc/link.md §Boss-event mapping).
function extractJsonValue(
  text: string,
  start: number,
  repair: boolean,
): string | undefined {
  const stack: string[] = [];
  let out = '';
  let inString = false;
  let escaped = false;
  for (let i = start; i < text.length; i++) {
    const ch = text[i];
    if (inString) {
      out += ch;
      if (escaped) escaped = false;
      else if (ch === '\\') escaped = true;
      else if (ch === '"') inString = false;
      continue;
    }
    if (ch === '"') {
      inString = true;
      out += ch;
      continue;
    }
    if (ch === '{' || ch === '[') {
      stack.push(ch === '{' ? '}' : ']');
      out += ch;
      continue;
    }
    if (ch === '}' || ch === ']') {
      if (repair) out = dropTrailingComma(out);
      out += ch;
      stack.pop();
      if (stack.length === 0) return out;
      continue;
    }
    out += ch;
  }
  if (!repair) return undefined;
  if (inString) out += '"';
  out = dropTrailingComma(out);
  while (stack.length > 0) out += stack.pop();
  return out;
}

// Tolerant JSON recovery shared by the classifier and adjudicator: prefer a
// strict balanced span at the earliest opening brace, then its repair, before
// advancing to a later candidate (slc/link.md §Boss-event mapping).
function parseJudgeJson(raw: string): unknown {
  const fenced = stripCodeFence(raw.trim());
  try {
    return JSON.parse(fenced);
  } catch {
    // Fall through to lenient extraction + repair.
  }
  const starts: number[] = [];
  for (let i = 0; i < fenced.length; i++) {
    const ch = fenced[i];
    if (ch === '{' || ch === '[') starts.push(i);
  }
  let firstValue: { value: unknown } | undefined;
  for (const start of starts) {
    let parsedHere: { value: unknown } | undefined;
    for (const repair of [false, true]) {
      const candidate = extractJsonValue(fenced, start, repair);
      if (candidate === undefined) continue;
      try {
        parsedHere = { value: JSON.parse(candidate) };
      } catch {
        continue;
      }
      break;
    }
    if (parsedHere === undefined) continue;
    if (isPlainObject(parsedHere.value)) return parsedHere.value;
    if (firstValue === undefined) firstValue = parsedHere;
  }
  if (firstValue !== undefined) return firstValue.value;
  throw new Error('adjudicate: judge response is not valid JSON');
}

type JudgePurpose = 'boss-input-classification' | 'player-output-adjudication';

interface RuntimeBoundaryCalls {
  callPlayer(
    input: PlayerInput,
    playerId: string,
    prompt: string,
    signal: AbortSignal,
  ): Promise<PlayerResult>;
  callJudge(
    purpose: JudgePurpose,
    stateId: string | undefined,
    prompt: string,
    signal: AbortSignal,
  ): Promise<string>;
}

// LLM-judge adjudicator (slc/link.md §Captain adjudication). Coerces the
// player's finalText into one of the state's declared guards, extracts every
// required payload field from the judge reply, and fails loudly (throws) on a
// missing JSON object, an undeclared guard, or a missing required field.
async function adjudicate(
  input: PlayerInput,
  finalText: string,
  ports: PlaybookPorts,
  signal: AbortSignal,
  boundary?: RuntimeBoundaryCalls,
): Promise<PlayerOutput> {
  const prompt = buildJudgePrompt(input, finalText);
  const raw = boundary
    ? await boundary.callJudge(
        'player-output-adjudication',
        input.stateId,
        prompt,
        signal,
      )
    : await ports.callJudge(prompt, signal);
  const parsed = parseJudgeJson(raw);
  if (typeof parsed !== 'object' || parsed === null || Array.isArray(parsed)) {
    throw new Error('adjudicate: judge response is not a JSON object');
  }
  const obj = parsed as Record<string, unknown>;
  const guard = obj.guard;
  if (typeof guard !== 'string') {
    throw new Error('adjudicate: judge response missing string "guard" field');
  }
  if (!Object.prototype.hasOwnProperty.call(input.result, guard)) {
    throw new Error(
      `adjudicate: unknown guard "${guard}" — declared guards: ${Object.keys(
        input.result,
      ).join(', ')}`,
    );
  }
  for (const field of extractRequiredFields(input.result[guard])) {
    if (typeof obj[field] !== 'string') {
      if (guard === 'needsBossReply' && field === 'question') {
        throw new Error(BOSS_REPLY_ERRORS.missingQuestion);
      }
      throw new Error(
        `adjudicate: judge response missing required field "${field}" for guard "${guard}"`,
      );
    }
  }
  return obj as unknown as PlayerOutput;
}

function validateBossReplyOutput(
  input: PlayerInput,
  output: PlayerOutput,
): void {
  if (output.guard !== 'needsBossReply') return;
  if (typeof output.question !== 'string') {
    throw new Error(BOSS_REPLY_ERRORS.missingQuestion);
  }
  if (!RESUMABLE_STATE_IDS.has(input.stateId)) {
    throw new Error(BOSS_REPLY_ERRORS.unregisteredState(input.stateId));
  }
}

interface ClassifierState {
  value: unknown;
  context: Record<string, unknown>;
}

function classifierState(snapshotOrState: unknown): ClassifierState {
  if (
    snapshotOrState !== null &&
    typeof snapshotOrState === 'object' &&
    'value' in snapshotOrState
  ) {
    const candidate = snapshotOrState as { value?: unknown; context?: unknown };
    return {
      value: candidate.value,
      context:
        candidate.context !== null &&
        typeof candidate.context === 'object' &&
        !Array.isArray(candidate.context)
          ? (candidate.context as Record<string, unknown>)
          : {},
    };
  }
  return { value: snapshotOrState, context: {} };
}

// Boss-message classifier prompt (slc/link.md §Boss-event mapping). Lists the
// events the current parked state accepts and includes the exact Boss text.
// The runtime-owned textual fields (START.task, BOSS_REPLY.answer) are not
// requested from the judge.
function buildClassifierPrompt(text: string, state: ClassifierState): string {
  const currentState =
    typeof state.value === 'string'
      ? state.value
      : JSON.stringify(state.value ?? null);
  const lines = [
    'Classify the following Boss message into exactly one of these events.',
    'Respond with JSON: { "event": "<TYPE>", "payload": { ...fields } }.',
    'Use { "event": "NO_ACTION", "payload": {} } when no FSM action should be taken.',
    '',
    `Current state: ${currentState}`,
  ];
  const pending = pendingBossQuestionFromContext(state.context);
  if (currentState === 'awaitBossReply') {
    if (pending !== undefined) {
      lines.push(
        `Pending question id: ${pending.questionId}`,
        `Pending asking player: ${pending.player}`,
        `Pending Boss question: ${pending.question}`,
      );
    }
    lines.push(
      '',
      'Events:',
      '- BOSS_REPLY: payload { questionId?: "<pending question id>" } — the acting agent is waiting for Boss to answer its question.',
      '- NO_ACTION: payload {}',
    );
  } else if (currentState === 'failed') {
    lines.push(
      '',
      'Events:',
      '- START: payload {} — restart the workflow from the beginning with this message as the task.',
      '- NO_ACTION: payload {}',
    );
  } else {
    lines.push('', 'Events:', '- NO_ACTION: payload {}');
  }
  lines.push('', 'Boss message:', '```', text, '```');
  return lines.join('\n');
}

// Classify a non-empty Boss turn against the current parked state. Returns the
// FSM event to send, or undefined for no action / unrecoverable reply.
async function classifyBossText(
  text: string,
  ports: PlaybookPorts,
  signal: AbortSignal,
  snapshotOrState: unknown,
  boundary?: RuntimeBoundaryCalls,
): Promise<WorkflowEvent | undefined> {
  const trimmed = text.trim();
  if (trimmed === '') return undefined;
  const state = classifierState(snapshotOrState);
  const stateId = typeof state.value === 'string' ? state.value : undefined;
  const prompt = buildClassifierPrompt(text, state);
  const raw = boundary
    ? await boundary.callJudge(
        'boss-input-classification',
        stateId,
        prompt,
        signal,
      )
    : await ports.callJudge(prompt, signal);
  let parsed: unknown;
  try {
    parsed = parseJudgeJson(raw);
  } catch {
    await ports.emitStatus('Classifier reply was not recoverable JSON');
    return undefined;
  }
  if (typeof parsed !== 'object' || parsed === null || Array.isArray(parsed)) {
    await ports.emitStatus('Classifier returned a non-object JSON response');
    return undefined;
  }
  const obj = parsed as Record<string, unknown>;
  const eventType = obj.event;
  if (typeof eventType !== 'string') {
    await ports.emitStatus('Classifier did not name an event type');
    return undefined;
  }
  const payload =
    typeof obj.payload === 'object' &&
    obj.payload !== null &&
    !Array.isArray(obj.payload)
      ? (obj.payload as Record<string, unknown>)
      : {};

  switch (eventType) {
    case 'NO_ACTION':
      return undefined;
    case 'START': {
      if (state.value !== 'failed') {
        await ports.emitStatus(
          'Classifier returned START outside a restartable state',
        );
        return undefined;
      }
      return { type: 'START', task: text };
    }
    case 'BOSS_REPLY': {
      if (state.value !== 'awaitBossReply') {
        await ports.emitStatus(
          'Classifier returned BOSS_REPLY outside awaitBossReply',
        );
        return undefined;
      }
      const pending = pendingBossQuestionFromContext(state.context);
      if (pending === undefined) {
        await ports.emitStatus(
          'Classifier returned BOSS_REPLY without a pending question',
        );
        return undefined;
      }
      if (
        payload.questionId !== undefined &&
        typeof payload.questionId !== 'string'
      ) {
        await ports.emitStatus(
          'Classifier supplied a non-string questionId for BOSS_REPLY',
        );
        return undefined;
      }
      if (
        typeof payload.questionId === 'string' &&
        payload.questionId !== pending.questionId
      ) {
        await ports.emitStatus(
          `Classifier supplied unknown questionId for BOSS_REPLY: ${payload.questionId}`,
        );
        return undefined;
      }
      return {
        type: 'BOSS_REPLY',
        answer: text,
        questionId: pending.questionId,
      };
    }
    default:
      await ports.emitStatus(
        `Classifier returned unknown event type: ${eventType}`,
      );
      return undefined;
  }
}

function isAbortFailure(error: unknown, signal: AbortSignal): boolean {
  return (
    signal.aborted &&
    (error === signal.reason || normalizeError(error).name === 'AbortError')
  );
}

function normalizeErrorFull(err: unknown): NormalizedError | undefined {
  if (err === undefined || err === null) return undefined;
  return normalizeError(err);
}

// Detached JSON-safe descriptor of an XState transition event: only the
// declared Boss-union payload fields, a validated actor output, and a
// normalized error member — never XState-internal fields (slc/link.md
// §Session lifecycle).
function normalizeTransitionEvent(event: unknown): JsonValue {
  if (event === null || typeof event !== 'object') {
    return snapshotJsonValue(event ?? null, 'FSM event');
  }
  const e = event as Record<string, unknown>;
  const out: Record<string, JsonValue> = {};
  if (typeof e.type === 'string') out.type = e.type;
  if (typeof e.task === 'string') out.task = e.task;
  if (typeof e.answer === 'string') out.answer = e.answer;
  if (typeof e.questionId === 'string') out.questionId = e.questionId;
  if (e.output !== undefined) {
    out.output = snapshotJsonValue(e.output, 'FSM event output');
  }
  if (e.error !== undefined) {
    out.error = snapshotJsonValue(normalizeError(e.error), 'FSM event error');
  }
  return snapshotJsonValue(out, 'FSM event');
}

